// Test: dangerous conditions should return red level
async function testComputeSeaStatusRed() {
  const result = functions.call('computeSeaStatus', {
    windSpeed: 30,      // strong wind — 40 penalty
    windGusts: 42,      // strong gusts
    waveHeight: 3.5,    // rough seas — 25 penalty
    precipitation: 6,   // heavy rain — 12 penalty
    pressure: 998,      // low pressure — 8 penalty
    cloudCover: 90
  });

  assertEquals(result.level, 'red', 'Dangerous conditions should be red');
  assertEquals(result.label, 'Dangerous');
  assert(result.score >= 15 && result.score < 40, 'Red score should be 15-39, got ' + result.score);
  assert(result.reasons.length >= 3, 'Should have multiple penalty reasons');
}
